enum ItemUpgradeReq { /// Item instance does not need to be upgraded, i.e. only state data type is changed. None, /// Item can and needs to be re-ensured as part of this upgrade. Modify, /// Item needs to be cleaned and re-ensured as part of this upgrade. Replace,
}

