// Traits in Peace Framework
trait Item { type Params: Params + Serialize + Deserialize; fn setup(&self, resources); fn try_state_current(fn_ctx, params_partial, data); fn try_state_goal(fn_ctx, params_partial, data); fn state_clean ( params_partial, data); fn state_current (fn_ctx, params, data); fn state_goal (fn_ctx, params, data); fn apply_dry (fn_ctx, params, data, state_current, state_target, diff); fn apply (fn_ctx, params, data, state_current, state_target, diff); fn apply_check ( params_partial, data, state_current, state_target, diff); fn state_diff ( params_partial, data, state_a, state_b); // Once more, with types: fn setup(&self, &mut Resources<Empty>); fn try_state_current(FnCtx<'_>, Self::Params<'_>::Partial, Self::Data<'_>); fn try_state_goal(FnCtx<'_>, Self::Params<'_>::Partial, Self::Data<'_>); fn state_clean ( Self::Params<'_>::Partial, Self::Data<'_>); fn state_current (FnCtx<'_>, Self::Params<'_> , Self::Data<'_>); fn state_goal (FnCtx<'_>, Self::Params<'_> , Self::Data<'_>); fn apply_dry (FnCtx<'_>, Self::Params<'_> , Self::Data<'_>, Self::State, Self::State, Self::StateDiff); fn apply (FnCtx<'_>, Self::Params<'_> , Self::Data<'_>, Self::State, Self::State, Self::StateDiff); fn apply_check ( Self::Params<'_>::Partial, Self::Data<'_>, Self::State, Self::State, Self::StateDiff); fn state_diff ( Self::Params<'_>::Partial, Self::Data<'_>, Self::State, Self::State);
} /// For Peace to access <Item::Params as Params>::Spec
trait Params { type Spec: Serialize + Deserialize; type SpecBuilder: SpecBuilder<Output = Self::Spec>; type Partial: Serialize + Deserialize;
} enum ValueSpec<T> { Value(T), From, FromMap(Box<dyn Fn(&Resources) -> Option<T>>),
} Also need to provide a Params derive macro. Design Note The apply_check and state_diff functions usually are not expected to need params and data, but some items may use them, such as the ShCmdItem which accesses params to determine the script to run. Regarding params will be Params or Params<'_>::Partial for state_diff, if we call state_diff for a file upload item, we must have both the current state and goal state. Then we need to ask, does having both states imply Params is fully resolvable? If we call state_current for a file upload: the destination server may not be there so params may not have the IP we may still return Some(State::Empty) So params may still be partial, even if State is Some. If we call state_goal for a file upload: the source file may not be there so params may not have the source content hash we may still return Some(State::Empty) So params may still be partial, even if State is Some.

